<script setup>
import { ref, computed, onMounted } from 'vue'
import { Star } from '@element-plus/icons-vue'
import { getHabits, toggleHabitComplete } from '../services/storage.js'

// 接收习惯数据作为props
const props = defineProps({
  habits: {
    type: Array,
    default: () => []
  }
})

// 存储展开的习惯ID
const expandedHabitId = ref(null)

// 切换习惯展开/收起状态
const toggleHabitExpand = (habitId) => {
  expandedHabitId.value = expandedHabitId.value === habitId ? null : habitId
}

// 获取当前星期几的索引：0=周日，1=周一，...，6=周六
const currentDayIndex = ref(new Date().getDay())

// 计算本周日期范围（从周日开始）
const getCurrentWeekDates = () => {
  const today = new Date()
  const currentDate = new Date(today)
  const weekStart = new Date(currentDate.setDate(today.getDate() - today.getDay()))
  const weekDates = []
  
  for (let i = 0; i < 7; i++) {
    const date = new Date(weekStart)
    date.setDate(weekStart.getDate() + i)
    weekDates.push(date)
  }
  
  return weekDates
}

const weekDates = ref(getCurrentWeekDates())

// 检查习惯在特定日期是否完成
const isHabitCompletedOnDate = (habit, date) => {
  if (!habit.completedDates) return false
  
  const dateStr = date.toISOString().split('T')[0]
  return habit.completedDates.includes(dateStr)
}

// 切换习惯在特定日期的完成状态
const toggleDay = async (habitId, dayIndex) => {
  const date = weekDates.value[dayIndex]
  await toggleHabitComplete(habitId, date)
  
  // 通知父组件数据已更新
  emit('update:habits', await getHabits())
}

// 定义emit
const emit = defineEmits(['update:habits'])

const getHabitIcon = (habit) => {
  const icons = {
    'Morning Exercise': '🏃‍♂️',
    'Read a Book': '📚',
    'Drink Water': '💧',
    'Meditate': '🧘‍♀️'
  }
  return icons[habit.name] || '📝'
}
</script>

<template>
  <div class="dashboard">
    <div class="dashboard-header">
      <h2>Track Your Habits Daily!</h2>
    </div>

    <el-card class="habits-container" shadow="hover" style="margin-top: 20px;">
      <el-table
        :data="props.habits"
        stripe
        style="width: 100%;"
        :row-key="(row) => row.id"
        @row-click="(row) => toggleHabitExpand(row.id)"
        :expanded-row-keys="[expandedHabitId]"
      >
        <!-- Habit Column -->
        <el-table-column label="Habit" min-width="300">
          <template #default="{ row }">
            <div class="habit-info">
              <span class="habit-icon">{{ getHabitIcon(row) }}</span>
              <span class="habit-name">{{ row.name }}</span>
            </div>
          </template>
        </el-table-column>

        <!-- Day Columns -->
        <el-table-column label="Sun" width="50" align="center">
          <template #header-cell="scope">
            <div class="header-cell day-column" :class="{ 'current-day': 0 === currentDayIndex.value }">{{ scope.column.label }}</div>
          </template>
          <template #default="{ row }">
            <div class="table-cell day-column" :class="{ 'current-day-column': 0 === currentDayIndex.value }">
              <div 
                class="day-icon"
                :class="{
                  'completed': isHabitCompletedOnDate(row, weekDates[0]),
                  'current-day-icon': 0 === currentDayIndex.value
                }"
                @click="toggleDay(row.id, 0)"
              >
                <span v-if="isHabitCompletedOnDate(row, weekDates[0])">✓</span>
              </div>
            </div>
          </template>
        </el-table-column>

        <el-table-column label="Mon" width="50" align="center">
          <template #header-cell="scope">
            <div class="header-cell day-column">{{ scope.column.label }}</div>
          </template>
          <template #default="{ row }">
            <div class="table-cell day-column">
              <div 
                class="day-icon"
                :class="{
                  'completed': isHabitCompletedOnDate(row, weekDates[1]),
                  'current-day-icon': 1 === currentDayIndex.value
                }"
                @click="toggleDay(row.id, 1)"
              >
                <span v-if="isHabitCompletedOnDate(row, weekDates[1])">✓</span>
              </div>
            </div>
          </template>
        </el-table-column>

        <el-table-column label="Tue" width="50" align="center">
          <template #header-cell="scope">
            <div class="header-cell day-column" :class="{ 'current-day': 2 === currentDayIndex.value }">{{ scope.column.label }}</div>
          </template>
          <template #default="{ row }">
            <div class="table-cell day-column" :class="{ 'current-day-column': 2 === currentDayIndex.value }">
              <div 
                class="day-icon"
                :class="{
                  'completed': isHabitCompletedOnDate(row, weekDates[2]),
                  'current-day-icon': 2 === currentDayIndex.value
                }"
                @click="toggleDay(row.id, 2)"
              >
                <span v-if="isHabitCompletedOnDate(row, weekDates[2])">✓</span>
              </div>
            </div>
          </template>
        </el-table-column>

        <el-table-column label="Wed" width="50" align="center">
          <template #header-cell="scope">
            <div class="header-cell day-column" :class="{ 'current-day': 3 === currentDayIndex.value }">{{ scope.column.label }}</div>
          </template>
          <template #default="{ row }">
            <div class="table-cell day-column" :class="{ 'current-day-column': 3 === currentDayIndex.value }">
              <div 
                class="day-icon"
                :class="{
                  'completed': isHabitCompletedOnDate(row, weekDates[3]),
                  'current-day-icon': 3 === currentDayIndex.value
                }"
                @click="toggleDay(row.id, 3)"
              >
                <span v-if="isHabitCompletedOnDate(row, weekDates[3])">✓</span>
              </div>
            </div>
          </template>
        </el-table-column>

        <el-table-column label="Thu" width="50" align="center">
          <template #header-cell="scope">
            <div class="header-cell day-column" :class="{ 'current-day': 4 === currentDayIndex.value }">{{ scope.column.label }}</div>
          </template>
          <template #default="{ row }">
            <div class="table-cell day-column" :class="{ 'current-day-column': 4 === currentDayIndex.value }">
              <div 
                class="day-icon"
                :class="{
                  'completed': isHabitCompletedOnDate(row, weekDates[4]),
                  'current-day-icon': 4 === currentDayIndex.value
                }"
                @click="toggleDay(row.id, 4)"
              >
                <span v-if="isHabitCompletedOnDate(row, weekDates[4])">✓</span>
              </div>
            </div>
          </template>
        </el-table-column>

        <el-table-column label="Fri" width="50" align="center">
          <template #header-cell="scope">
            <div class="header-cell day-column" :class="{ 'current-day': 5 === currentDayIndex.value }">{{ scope.column.label }}</div>
          </template>
          <template #default="{ row }">
            <div class="table-cell day-column" :class="{ 'current-day-column': 5 === currentDayIndex.value }">
              <div 
                class="day-icon"
                :class="{
                  'completed': isHabitCompletedOnDate(row, weekDates[5]),
                  'current-day-icon': 5 === currentDayIndex.value
                }"
                @click="toggleDay(row.id, 5)"
              >
                <span v-if="isHabitCompletedOnDate(row, weekDates[5])">✓</span>
              </div>
            </div>
          </template>
        </el-table-column>

        <el-table-column label="Sat" width="50" align="center">
          <template #header-cell="scope">
            <div class="header-cell day-column" :class="{ 'current-day': 6 === currentDayIndex.value }">{{ scope.column.label }}</div>
          </template>
          <template #default="{ row }">
            <div class="table-cell day-column" :class="{ 'current-day-column': 6 === currentDayIndex.value }">
              <div 
                class="day-icon"
                :class="{
                  'completed': isHabitCompletedOnDate(row, weekDates[6]),
                  'current-day-icon': 6 === currentDayIndex.value
                }"
                @click="toggleDay(row.id, 6)"
              >
                <span v-if="isHabitCompletedOnDate(row, weekDates[6])">✓</span>
              </div>
            </div>
          </template>
        </el-table-column>

        <!-- Streak Column -->
        <el-table-column label="Streak" width="120" align="center">
          <template #default="{ row }">
            <div class="streak-info">
              <el-tag type="warning">
                <el-icon><Star /></el-icon> {{ row.streak || 0 }} days
              </el-tag>
              <div class="progress-bar">
                <div 
                  class="progress-fill"
                  :style="{ width: `${((row.streak || 0) / 30) * 100}%` }"
                ></div>
              </div>
            </div>
          </template>
        </el-table-column>
        
        <!-- Expandable Row Column -->
        <el-table-column type="expand">
          <template #default="{ row }">
            <div class="habit-detail">
              <h3>习惯详情</h3>
              <div class="detail-item">
                <span class="detail-label">描述：</span>
                <span class="detail-value">{{ row.description || '暂无描述' }}</span>
              </div>
              <div class="detail-item">
                <span class="detail-label">创建时间：</span>
                <span class="detail-value">{{ new Date(row.createdAt).toLocaleString() }}</span>
              </div>
            </div>
          </template>
        </el-table-column>
      </el-table>
    </el-card>
  </div>
</template>

<style scoped>
.dashboard {
  width: 100%;
}

.dashboard-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 30px;
}

.dashboard-header h2 {
  margin: 0;
  font-size: 28px;
  color: var(--text-primary);
}

/* 确保表头和表格单元格对齐 */
.header-cell, .table-cell {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  width: 100%;
}

/* 当前天的列背景 */
.header-cell.current-day {
  background-color: var(--primary-color);
  color: white;
  border-radius: 4px;
}

/* 当前天的列背景 */
.table-cell.current-day-column {
  background-color: rgba(50, 112, 202, 0.05);
}

.day-icon {
  width: 32px;
  height: 32px;
  border: 2px solid #e0e0e0;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all var(--transition-fast);
  background-color: white;
}

.day-icon:hover {
  border-color: var(--primary-color);
}

.day-icon.completed {
  background-color: var(--success-color);
  border-color: var(--success-color);
  color: white;
  font-weight: bold;
}

/* 当前天的圆圈样式 */
.day-icon.current-day-icon {
  border-color: var(--primary-color);
  background-color: rgba(50, 112, 202, 0.1);
}

.progress-bar {
  width: 80px;
  height: 4px;
  background-color: #e0e0e0;
  border-radius: 2px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  background-color: var(--success-color);
  transition: width var(--transition-normal);
}

/* 习惯详情样式 */
.habit-detail {
  padding: 16px;
  background-color: rgba(0, 0, 0, 0.02);
  border-radius: 8px;
  margin: 8px 0;
}

.habit-detail h3 {
  margin-top: 0;
  margin-bottom: 16px;
  font-size: 18px;
  color: var(--text-primary);
}

.detail-item {
  margin-bottom: 12px;
  display: flex;
  align-items: flex-start;
}

.detail-label {
  font-weight: bold;
  width: 100px;
  color: var(--text-primary);
}

.detail-value {
  flex: 1;
  color: var(--text-secondary);
  word-break: break-word;
}

.completed-date-tag {
  margin-right: 8px;
  margin-bottom: 8px;
}
</style>